firmware_template.source:
#include "pcf8574.h"
#include <Wire.h>
#include <PCF8574.h>
static PCF8574 pcf(0x20);
void pcf8574_setup(){Wire.begin();if(!pcf.begin()){Serial.println("[pcf8574] Fail!");return;}Serial.println("[pcf8574] OK");}
void pcf8574_write(uint8_t p,bool v){pcf.write(p,v?HIGH:LOW);}
bool pcf8574_read(uint8_t p){return pcf.read(p)==HIGH;}
void pcf8574_write_byte(uint8_t v){pcf.write8(v);}
uint8_t pcf8574_read_byte(){return pcf.read8();}
